import{c as s}from"./DSWU3toF.js";const n={async login(t,e){return(await s.post("/auth/login",{username:t,password:e})).data},async signup(t){return(await s.post("/auth/register",t)).data},async refresh(){return(await s.post("/auth/refresh",null,{withCredentials:!0})).data},async logout(){await s.post("/auth/logout")},async getDepartments(){return(await s.get("/auth/departments")).data},async getProgrammes(){return(await s.get("/auth/programmes")).data}};export{n as a};
